import React from 'react';
import clsx from 'clsx';
import { useCssScope } from '../config-provider/hooks';
import Line from './Line';
import Circle from './Circle';
import type { ProgressProps } from './shared';

import './style';

export const Progress: React.FC<ProgressProps> = (props, refs) => {
  const { type = 'line', percent = 0, className, style } = props;

  let optimizePercent = 0;
  if (percent > 100) {
    optimizePercent = 100;
  } else if (percent < 0) {
    optimizePercent = 0;
  } else {
    optimizePercent = percent;
  }

  const cssScope = useCssScope('progress');

  const renderProgress = () => {
    let progressNode;
    switch (type) {
      case 'line':
        progressNode = <Line {...props} percent={optimizePercent} />;
        break;
      case 'circle': {
        progressNode = <Circle {...props} percent={optimizePercent} />;
      }
      default:
        break;
    }
    return progressNode;
  };

  return (
    <div style={style} className={clsx(cssScope(), cssScope(`--${type}`), className)}>
      <div className={cssScope(`--${type}-wrapper`)}>{renderProgress()}</div>
    </div>
  );
};
